class SuperValidator:

    @staticmethod
    def validate_object_structure(data: Dict[str, Any]) -> List[str]:
        """Valide la structure d'un objet JSON avant insertion en base."""
        errors = []

        if not isinstance(data, dict):
            return ["Entrée invalide : doit être un dictionnaire."]

        if "_comment" in data and len(data) == 1:
            return []  # commentaire global : pas d'erreur

