            if key in data and not isinstance(data[key], list):
                errors.append(f"Le champ '{key}' doit être une liste.")

        return errors

    @staticmethod
    def validate_form_input(data: Dict[str, Any], required_fields: List[str], types: Dict[str, type]) -> List[str]:
        errors = []

        for field in required_fields:
            if field not in data:
                errors.append(f"Champ requis manquant : {field}")

        for field, expected_type in types.items():
            if field in data and not isinstance(data[field], expected_type):
                errors.append(f"Le champ '{field}' doit être de type {expected_type.__name__}")

        return errors

    @staticmethod
    def validate_url_path(path: str) -> Union[bool, str]:
        if not path.startswith("/"):
            return "L'URL doit commencer par un /"
        if ".." in path or "//" in path:
            return "Chemin URL invalide (.. ou // interdit)"
        if not re.match(r"^/[a-zA-Z0-9/_-]*$", path):
            return "Chemin URL contient des caractères non autorisés"
        return True

    @staticmethod
    def validate_email(email: str) -> bool:
        return bool(re.match(r"^[\w\.-]+@[\w\.-]+\.\w{2,4}$", email))

    @staticmethod
    def validate_enum(value: Any, allowed_values: List[Any]) -> bool:
        return value in allowed_values

    @staticmethod
    def rules_from_metaclass(metaclass: Dict[str, Any]) -> Dict[str, Any]:
        """Génère dynamiquement les règles à partir d'une définition de MetaClass."""
        rules = {}
        metas = metaclass.get("metas", [])
        for m in metas:
            nom = m.get("nom")
            type_ = m.get("type", "str")
            if nom:
                rules[nom] = SuperValidator._python_type(type_)
        return rules

    @staticmethod
    def _python_type(type_str: str) -> type:
        """Mappe un type logique/metaclass vers un type Python basique pour validation."""
        return {
            "String": str,
            "Text": str,
            "Float": float,
            "Int": int,
            "Bool": bool,
            "List": list,
            "Dict": dict,
            "Enum": str,
            "Date": str,
        }.get(type_str, str)  # Par défaut string si inconnu"
    }
  ]
}

