export default function FormBuilder({ formId }) {
  const [form, setForm] = useState(null)
  const [components, setComponents] = useState([])

  useEffect(() => {
    fetch(`/api/get_form_definition?form=${formId}`)
      .then(res => res.json())
      .then(data => {
        setForm(data.form)
        setComponents(data.components)
      })
  }, [formId])

  if (!form) return <div>Chargement...</div>

  return (
    <form action={form.action_cible} method={form.méthode} className={form.style?.class || ''}>
      {components
        .sort((a, b) => (a.ordre || 0) - (b.ordre || 0))
        .map((comp, i) => (
          <div key={i} className={comp.style?.class || 'mb-3'}>
            <label htmlFor={comp.nom_champ}>{comp.label}</label>
            {renderField(comp)}
          </div>
        ))}
      <button type="submit" className="btn btn-primary">Envoyer</button>
    </form>
  )
}

function renderField(comp) {
  const commonProps = {
    name: comp.nom_champ,
    required: comp.obligatoire,
    className: comp.style?.inputClass || 'form-control',
  }

  switch (comp.type_champ) {
    case 'textarea':
      return <textarea {...commonProps} />
    case 'select':
      return (
        <select {...commonProps}>
          {(comp.valeurs_autorisées || []).map((v, i) => (
            <option key={i} value={v}>{v}</option>
          ))}
        </select>
      )
    case 'email':
    case 'number':
    case 'password':
    case 'date':
    case 'hidden':
      return <input type={comp.type_champ} {...commonProps} />
    default:
      return <input type="text" {...commonProps} />
  }
}"}

