  "name": "superloader",
  "type": "code/python",
  "content": "# :name: superloader
# :description: Charge dynamiquement une fonction, classe ou module en fonction de son type, nom et paramètres.
# :type: core_tool
# :folder: Nuclei/structura/supertools
# :inputs: object_type (str), object_name (str), params (dict), is_instance (bool)
# :outputs: objet exécutable ou instance de classe
# :tags: [dynamic, import, loader, introspection, modular, metaprogramming]

def SuperLoader(object_type: str, object_name: str, params: dict = {}, is_instance: bool = False):
    """
    Charge dynamiquement une fonction, classe ou module à partir de son type, nom et paramètres.
    - object_type : "Function", "Class", "MetaClass"
    - object_name : nom de la fonction ou classe à charger
    - params : dictionnaire des paramètres pour l'appel
    - is_instance : si True, retourne une instance (pour une classe)
    """
    base_path = "Organismus.Corpus.Mesoderma.Pulmo_Filterum.actions"
    module_path = f"{base_path}.{object_name}"

    try:
        module = __import__(module_path, fromlist=[object_name])
        obj_class = getattr(module, object_name)

        if is_instance:
            return obj_class(**params)
        else:
            return obj_class if not params else obj_class(**params)

    except ModuleNotFoundError:
        raise ImportError(f"Module introuvable : {module_path}")
    except AttributeError:
        raise ImportError(f"Objet '{object_name}' introuvable dans {module_path}")
    except Exception as e:
        raise RuntimeError(f"Erreur lors du chargement de {object_name} : {str(e)}")"
}

